API này cung cấp các chức năng cơ bản để quản lý danh sách các sản phẩm.  Bạn có thể mở rộng API này bằng cách thêm các tính năng khác, chẳng hạn như phân trang, lọc và xác thực.

```python
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

tasks = {}

class Task(BaseModel):
    title: str
    description: str

@app.get('/tasks')
def get_tasks():
    return tasks

@app.post('/tasks')
def create_task(task: Task):
    task_id = len(tasks) + 1
    tasks[task_id] = task
    return {'task_id': task_id, **task.dict()}

@app.get('/tasks/{task_id}')
def get_task(task_id: int):
    if task_id not in tasks:
        raise HTTPException(status_code=404, detail='Task not found')
    return tasks[task_id]

@app.put('/tasks/{task_id}')
def update_task(task_id: int, task: Task):
    if task_id not in tasks:
        raise HTTPException(status_code=404, detail='Task not found')
    tasks[task_id] = task
    return tasks[task_id]

@app.delete('/tasks/{task_id}')
def delete_task(task_id: int):
    if task_id not in tasks:
        raise HTTPException(status_code=404, detail='Task not found')
    del tasks[task_id]
    return {'message': 'Task deleted'}
```

